Read p-values

read_normal_pvalues &lt;- function(n, discretize) {
  file &lt;- paste0(
    "../results/normal/normal_iid_n", n,
    "_discretize_", discretize,
    "_pvalues.rds"
  )

  if (!file.exists(file)) {
    stop("File does not exist: ", file)
  }

  pvals &lt;- readRDS(file)

  tibble(
    n = n,
    discretize = discretize,
    rep = seq_along(pvals),
    cvm_pvalue = map_dbl(pvals, 1),
    ad_pvalue = map_dbl(pvals, 2)
  )
}

normal_results &lt;- expand.grid(
  n = sample_sizes,
  discretize = discretize_values
) |&gt;
  pmap_dfr(function(n, discretize) {
    read_normal_pvalues(n, discretize)
  })

normal_long &lt;- normal_results |&gt;
  tidyr::pivot_longer(
    cols = c(cvm_pvalue, ad_pvalue),
    names_to = "method",
    values_to = "pvalue"
  ) |&gt;
  mutate(
    method = recode(
      method,
      cvm_pvalue = "CvM",
      ad_pvalue = "AD"
    )
  )

